const sessionId = $json.session_id;
const message = $json.message;

if (!sessionId || typeof sessionId !== 'string' || !sessionId.trim()) {
  throw new Error('session_id is required');
}

if (!message || typeof message !== 'string' || !message.trim()) {
  throw new Error('message is required');
}

return items;

const blockedPatterns = [
  'ignore previous instructions',
  'reveal system prompt',
  'act as system',
  'bypass safeguards',
  'jailbreak',
];

const message = String($json.message || '').toLowerCase();
const blocked = blockedPatterns.some((pattern) => message.includes(pattern));

if (blocked) {
  return [{
    json: {
      ...$json,
      response: 'Your request cannot be processed due to security restrictions.'
    }
  }];
}

return items;

if ($json.response) {
  return items;
}

const emergencyPhrases = [
  'chest pain',
  "can't breathe",
  'stroke',
  'severe bleeding',
  'suicide',
  'anaphylaxis',
];

const message = String($json.message || '').toLowerCase();
const isEmergency = emergencyPhrases.some((phrase) => message.includes(phrase));

if (isEmergency) {
  return [{
    json: {
      ...$json,
      response: 'Your symptoms may require urgent medical attention. Call 999 immediately or contact NHS 111.'
    }
  }];
}

return [{ json: { ...$json } }];

